1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
14	
15	const BASE_PRICES: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	const BLOCK_PRICE: Record<string, number> = {
26	  rune: 60,
27	  moonstone: 60,
28	};
29	
30	export interface QuoteContext {
31	  previousQuoteCount?: number;
32	}
33	
34	export function quote(customer: Customer, items: Item[], context?: QuoteContext): number {
35	  let total = 0;
36	  let policyBase = 0;
37	  const componentCounts: Record<string, number> = {};
38	  for (const item of items) {
39	    if (COMPONENT_TYPES.has(item.type)) {
40	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
41	      continue;
42	    }
43	    const base = BASE_PRICES[item.type] ?? 0;
44	    const curse = item.cursed ? base * 0.5 : 0;
45	    const highEnchant = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
46	    total += base + curse + highEnchant + base * FIRST_INSURANCE_SURCHARGE_RATE;
47	    policyBase += base;
48	  }
49	  for (const type of Object.keys(componentCounts)) {
50	    const count = componentCounts[type];
51	    const unitPrice = BASE_PRICES[type] ?? 0;
52	    const base = count === 3 ? BLOCK_PRICE[type] : unitPrice * count;
53	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
54	    policyBase += base;
55	  }
56	  if (customer.yearsWithMHPCO >= 2) {
57	    total -= policyBase * 0.2;
58	  }
59	  if ((context?.previousQuoteCount ?? 0) > 0) {
60	    total -= policyBase * 0.15;
61	  }
62	  total += PROCESSING_FEE;
63	  return Math.ceil(total);
64	}
65	
66	export function claim(): unknown {
67	  return undefined;
68	}
